function parseSemVer(version) {
  const plusIdx = version.indexOf('+');
  const core = plusIdx === -1 ? version : version.slice(0, plusIdx);
  const dashIdx = core.indexOf('-');
  const numericPart = dashIdx === -1 ? core : core.slice(0, dashIdx);
  const preRelease = dashIdx === -1 ? null : core.slice(dashIdx + 1);
  const [major, minor, patch] = numericPart.split('.').map(Number);
  const preIds = preRelease ? preRelease.split('.') : null;
  return { major, minor, patch, preIds };
}

function comparePreIds(aIds, bIds) {
  const len = Math.max(aIds.length, bIds.length);
  for (let i = 0; i < len; i++) {
    if (i >= aIds.length) return -1;
    if (i >= bIds.length) return 1;
    const aId = aIds[i];
    const bId = bIds[i];
    const aNum = /^\d+$/.test(aId);
    const bNum = /^\d+$/.test(bId);
    if (aNum && bNum) {
      const diff = Number(aId) - Number(bId);
      if (diff !== 0) return diff;
    } else {
      if (aId < bId) return -1;
      if (aId > bId) return 1;
    }
  }
  return 0;
}

function compareVersions(a, b) {
  const pa = parseSemVer(a);
  const pb = parseSemVer(b);
  if (pa.major !== pb.major) return pa.major - pb.major;
  if (pa.minor !== pb.minor) return pa.minor - pb.minor;
  if (pa.patch !== pb.patch) return pa.patch - pb.patch;
  if (pa.preIds === null && pb.preIds === null) return 0;
  if (pa.preIds === null) return 1;
  if (pb.preIds === null) return -1;
  return comparePreIds(pa.preIds, pb.preIds);
}

function sortVersions(versions) {
  return versions.slice().sort(compareVersions);
}

